<template>
  <div>
    <div class="titleBar">
      <span>監測編碼維護</span>
    </div>
    <div class="titleSearch">
      <table width="100%">
        <tr>
          <td class="titleTD01">功能</td>
          <td class="titleTD02" colspan="5"><input type="button" class="btnClass" value="新增監測編碼"></td>
        </tr>
        <tr>
          <td class="titleTD01" width="10%">監測項目</td>
          <td class="titleTD02" width="27%">
            <select name="monitorValue" v-model="monitorValue">
              <option v-for="(monitorItem, monitorKey) in monitorArr" :key="monitorKey" :value="monitorItem.MN_COD">{{ monitorItem.MN_NAM }}</option>
            </select>
          </td>
          <td class="titleTD01" width="10%">檢體來源</td>
          <td class="titleTD02" width="23%">
            <select name="sourceValue" v-model="sourceValue">
              <option v-for="(sourceItem, sourceKey) in sourceArr" :key="sourceKey" :value="sourceItem.item">{{ sourceItem.item }}</option>
            </select>
            </td>
          <td class="titleTD01" width="10%">狀態</td>
          <td class="titleTD02" width="20%">
            <select name="tsc" v-model="tsc">
              <option v-for="(tscItem, tscKey) in tscArr" :key="tscKey" :value="tscKey">{{ tscItem }}</option>
            </select>
          </td>
        </tr>
      </table>
    </div>
    <div style="padding:5px;">
      <input type="button" class="btnClass" value="查詢" @click="getDataFunc">
    </div>
    <div>
      <table width="100%">
        <tr class="dataTR01">
          <td>#</td>
          <td>編輯</td>
          <td>監測編碼</td>
          <td>監測項目</td>
          <td>檢體來源</td>
          <td>生效日期</td>
          <td>失效日期</td>
          <td>狀態</td>
          <td>異動人員</td>
          <td>異動時間</td>
        </tr>
        <tr class="dataTR02" v-for="(aItem, aIdx) in getDataList" :key="aIdx">
          <td>{{ aIdx + 1 }}</td>
          <td><i class="bi bi-pencil-square"></i></td>
          <td>{{ aItem.MN_COD }}</td>
          <td>{{ aItem.MN_NAM }}</td>
          <td>{{ aItem.srcNam }}</td>
          <td>{{ aItem.EFF_DAT }}</td>
          <td>{{ aItem.STP_DAT }}</td>
          <td>{{ tscArr[aItem.TSC] }}</td>
          <td>{{ aItem.RTP }} {{ getEmpList[aItem.RTP] }}</td>
          <td>{{ aItem.RTT }}</td>
        </tr>
      </table>
    </div>
  </div>
</template>

<script>
const Base64 = require('js-base64').Base64

export default {
  name: 'day14',
  data () {
    return {
      monitorValue: '',
      monitorArr: [],
      sourceValue: '請選擇',
      sourceArr: [{'item': '請選擇'}, {'item': '水質'}, {'item': '器械'}, {'item': '環境'}, {'item': '人員'}],
      tsc: 'A',
      tscArr: {'A': '生效', 'D': '取消'},
      getList: [],
      getSearchList: [],
      getEmpList: {}
    }
  },
  mounted () {
    this.getApiData()
    this.getEmpData()
    // var vm = this
    // vm.monitorArr = [{'MN_COD': '', 'MN_NAM': '請選擇監測項目'}]
    // vm.getList = []
    // var tag = 'pvt.if.getMnCodData'
    // var api = 'http://10.6.51.133/EIP/gows.php'
    // let param = new FormData()
    // let conf = {
    //   params: {
    //     wtag: tag
    //   }
    // }
    // let obj = {
    //   wb_base64: 0,
    //   encode: 'N',
    //   TSC: 'A'
    // }
    // param.append('var', Base64.encode(JSON.stringify(obj)))
    // // 傳入參數回傳結果
    // this.$axios
    //   .post(api, param, conf)
    //   .then(function (response) {
    //     // status 2000 呼叫成功
    //     // console.log(response)
    //     let result = JSON.parse(Base64.decode(response.data))
    //     console.log(result)
    //     if (result.sts === '000000') {
    //       // console.log('呼叫WS成功===>')
    //       let getVal = result.val
    //       for (var index in getVal) {
    //         // set檢體項目array
    //         vm.monitorArr.push({'MN_COD': getVal[index]['MN_COD'], 'MN_NAM': Base64.decode(getVal[index]['MN_NAM'])})
    //         // set資料array
    //         vm.getList.push({
    //           'MN_NO': getVal[index]['MN_NO'],
    //           'MN_COD': getVal[index]['MN_COD'],
    //           'MN_NAM': Base64.decode(getVal[index]['MN_NAM']),
    //           'srcNam': Base64.decode(getVal[index]['srcNam']),
    //           'EFF_DAT': getVal[index]['EFF_DAT'],
    //           'STP_DAT': getVal[index]['STP_DAT'],
    //           'TSC': getVal[index]['TSC'],
    //           'RTP': getVal[index]['RTP'],
    //           'RTT': getVal[index]['RTT']
    //         })
    //       }
    //     } else {
    //       console.log(result.sts, result.msg)
    //     }
    //   })
    //   .catch(function (error) {
    //     console.log(error)
    //   })
  },
  computed: {
    getDataList: function () {
      var vm = this
      return vm.getSearchList
    }
  },
  methods: {
    async getApiData () {
      var vm = this
      vm.monitorArr = [{'MN_COD': '', 'MN_NAM': '請選擇監測項目'}]
      vm.getList = []
      // START:呼叫TAG-------------------------------------------
      var tag = 'pvt.if.getMnCodData'
      let param = {
        wb_base64: '0',
        wb_big5: '0',
        encode: 'N',
        TSC: 'A'
      }
      let result = await this.$gows.callWS(tag, param)
      // END:呼叫TAG-------------------------------------------
      console.log(result)
      if (result.sts === '000000') {
        // console.log('呼叫WS成功===>')
        let getVal = result.val
        for (var index in getVal) {
          // set檢體項目array
          vm.monitorArr.push({'MN_COD': getVal[index]['MN_COD'], 'MN_NAM': Base64.decode(getVal[index]['MN_NAM'])})
          // set資料array
          vm.getList.push({
            'MN_NO': getVal[index]['MN_NO'],
            'MN_COD': getVal[index]['MN_COD'],
            'MN_NAM': Base64.decode(getVal[index]['MN_NAM']),
            'srcNam': Base64.decode(getVal[index]['srcNam']),
            'EFF_DAT': getVal[index]['EFF_DAT'],
            'STP_DAT': getVal[index]['STP_DAT'],
            'TSC': getVal[index]['TSC'],
            'RTP': getVal[index]['RTP'],
            'RTT': getVal[index]['RTT']
          })
        }
      } else {
        console.log(result.sts, result.msg)
      }
    },
    async getEmpData () {
      var vm = this
      vm.getEmpList = {}
      // START:呼叫TAG-------------------------------------------
      var tag = 'lib.uc.getpsepbdat'
      let param = {
        wb_base64: '0',
        wb_big5: '0',
        encode: 'N',
        type: 'A'
      }
      let result = await this.$gows.callWS(tag, param)
      // // END:呼叫TAG-------------------------------------------
      console.log(result)
      if (result.sts === '000000') {
        // console.log('呼叫WS成功===>')
        let getVal = result.val
        for (var index in getVal) {
          // set員工array
          // WS回傳值有先 urlencode 再 base64_encode
          let empNo = getVal[index]['emp_no']
          let empNam = decodeURIComponent(Base64.decode(getVal[index]['emp_nam']))
          empNam = empNam.replace('++++', '')
          vm.getEmpList[empNo] = empNam
        }
      } else {
        console.log(result.sts, result.msg)
      }
    },
    getDataFunc () {
      // console.log('getDataFunc')
      var vm = this
      vm.getSearchList = []
      vm.getList.forEach(function (element, index, array) {
        let isOkay = true
        if (vm.monitorValue) {
          if (vm.monitorValue !== element.MN_COD) {
            isOkay = false
          }
        } else {
          if (vm.sourceValue !== '請選擇') {
            if (vm.sourceValue !== element.srcNam) {
              isOkay = false
            }
          }
        }
        if (vm.tsc !== element.TSC) {
          isOkay = false
        }
        if (isOkay) {
          vm.getSearchList.push(element)
        }
      })
    }
  }
}
</script>

<style>
select {
  border-radius: 5px;
  height: 3vmin;
}
.titleBar {
  background-color:steelblue;
  color: #FFFFFF;
  text-align:left;
  padding: 5px;
}
.titleSearch {
  text-align:left;
}
.titleTD01 {
  background-color:rgb(199, 230, 250);
  padding: 4px;
  border: 1px solid rgb(199, 230, 250);
}
.titleTD02 {
  background-color:rgb(235, 244, 252);
  padding-left: 5px;
  border: 1px solid rgb(217, 228, 236);
}
.btnClass {
  border-radius: 5px;
  border: 1px solid steelblue;
  background-color: steelblue;
  color:white;
  padding: 2px 6px 0px 6px;
}
.btnClass:hover {
  border: 1px solid rgb(23, 102, 167);
  background-color: rgb(23, 102, 167);
}
.bi-pencil-square {
  color:rgb(114, 111, 111);
  cursor: pointer;
  font-size: 18px;
}
.bi-pencil-square:hover {
  color:dodgerblue;
}
.dataTR01 td {
  background-color: steelblue;
  color: white;
  padding: 2px;
  border: 1px solid rgb(199, 230, 250);
}
.dataTR02 td {
  background-color: rgb(228, 234, 240);
  color: 000000;
  padding: 2px;
  border: 1px solid #FFFFFF;
}
</style>



