<template>
  <div>
    <div class="card" style="text-align:left;">
      <h2>練習一</h2>
      <div>
          <img :src="getImage">
      </div>
    </div>
    <div class="card" style="text-align:left;">
      <h2>練習二－API 資料</h2>
      <div>
          <p v-if="getApiData">{{ getApiData }}</p>
      </div>
    </div>
  </div>
</template>

<script>
import image from '../../assets/pass.png'

export default {
  name: 'day10',
  data () {
    return {
      getImage: image,
      getApiData: ''
    }
  },
  created () {
    console.log(this.$route.params.id)
    const id = this.$route.params.id
    this.$http.get(`https://randomuser.me/api/?seed=${id}`).then((response) => {
      // console.log(response)
      for (var index in response) {
        if (index === 'data') {
          console.log(response[index]['results'])
          this.getApiData = response[index]['results']
        }
      }
    })
  }
}
</script>

<style>
</style>



