<template>
  <div>
    <div class="card" style="text-align:left;">
      <p>查看哪個縣市的氣象：
      <select name="countryValue" v-model="countryValue" @change="getCountryWeather">
        <option v-for="(cItem, cKey) in countryArr" :key="cKey" :value="cItem.key">{{ cItem.name }}</option>
      </select>
      </p>
      <div>
        <span>地區：{{ getNowData.location }}</span><br>
        <span>{{ getNowData.minT }}～{{ getNowData.maxT }}</span><br>
        <span>降雨機率：{{ getNowData.rain }}％</span><br>
        <span>{{ getNowData.weather }}</span>
      </div>
      <br>
      <div class="weatherDiv">
        <h1 style="text-align:center;">{{ locationName }}'s weather</h1>
        <h5 style="color:grey;text-align:center;">Today：{{ getToday }}</h5>
        <div class="temperDiv">
          <br>
          <span style="font-weight:bold;font-size:3vmin">{{ nowTemper }} C</span><br>
          <span style="font-weight:bold;">Feels like<br>{{ parseInt(nowTemper - 2) }} C</span>
        </div>
        <div style="color:#FFFFFF;float:left;">1234</div>
        <div class="picDiv">
          <i class="bi" :class="weatherClass"></i><br>
          <span style="font-weight:bold;">{{ nowWeather }}</span>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day15',
  data () {
    return {
      getToday: '',
      countryValue: '',
      countryArr: [],
      getApiData: [],
      getNowData: {location: '', minT: '', maxT: '', rain: '', weather: ''},
      nowTemper: '',
      nowWeather: '',
      weatherClass: '',
      locationName: ''
    }
  },
  mounted () {
    var today = new Date()
    today = '' + today
    var newArr = today.split(' ')
    this.getToday = newArr[1] + ' ' + newArr[2] + ', ' + newArr[3]
    this.getWeather()
    this.getTemper()
  },
  methods: {
    getWeather () {
      // 抓當下的時間
      var d = new Date()
      var month = d.getMonth() + 1
      var day = d.getDate()
      var hour = d.getHours()
      var minu = d.getMinutes()
      var secd = d.getSeconds()
      var today = d.getFullYear() + '-' + (month < 10 ? '0' : '') + month + '-' + (day < 10 ? '0' : '') + day + ' ' + (hour < 10 ? '0' : '') + hour + ':' + (minu < 10 ? '0' : '') + minu + ':' + (secd < 10 ? '0' : '') + secd
      var vm = this
      vm.countryArr = []
      vm.countryArr.push({key: '', name: '請選擇縣市'})
      var id = 'F-C0032-001'
      this.$axios
        .get(`https://opendata.cwb.gov.tw/api/v1/rest/datastore/${id}?Authorization=CWB-566765E6-6F28-488F-9C87-1A3B3959DC81&format=JSON`)
        .then(function (response) {
          // console.log(response.data.records.location)
          let lcData = response.data.records.location
          for (var index in lcData) {
            let lnam = lcData[index].locationName
            let weatherArr = lcData[index].weatherElement
            var minT = 0
            var maxT = 0
            var Wx = ''
            var WxValue = 0
            for (var wIdx in weatherArr) {
              if (weatherArr[wIdx].elementName === 'MinT' || weatherArr[wIdx].elementName === 'MaxT') {
                // console.log(weatherArr[wIdx].time)
                for (var tIdx in weatherArr[wIdx].time) {
                  let sDate = weatherArr[wIdx].time[tIdx].startTime
                  let eDate = weatherArr[wIdx].time[tIdx].endTime
                  if ((Date.parse(today).valueOf() >= Date.parse(sDate).valueOf()) && (Date.parse(today).valueOf() < Date.parse(eDate).valueOf())) {
                    if (weatherArr[wIdx].elementName === 'MinT') {
                      minT = weatherArr[wIdx].time[tIdx].parameter.parameterName
                    }
                    if (weatherArr[wIdx].elementName === 'MaxT') {
                      maxT = weatherArr[wIdx].time[tIdx].parameter.parameterName
                    }
                    break
                  } else {
                    if (Date.parse(today).valueOf() < Date.parse(sDate).valueOf()) {
                      if (weatherArr[wIdx].elementName === 'MinT') {
                        minT = weatherArr[wIdx].time[tIdx].parameter.parameterName
                      }
                      if (weatherArr[wIdx].elementName === 'MaxT') {
                        maxT = weatherArr[wIdx].time[tIdx].parameter.parameterName
                      }
                      break
                    }
                  }
                }
              }
            }
            for (var wxIdx in weatherArr) {
              if (weatherArr[wxIdx].elementName === 'Wx') {
                let sDate = weatherArr[wxIdx].time[tIdx].startTime
                let eDate = weatherArr[wxIdx].time[tIdx].endTime
                if ((Date.parse(today).valueOf() >= Date.parse(sDate).valueOf()) && (Date.parse(today).valueOf() < Date.parse(eDate).valueOf())) {
                  Wx = weatherArr[wxIdx].time[tIdx].parameter.parameterName
                  break
                } else {
                  if (Date.parse(today).valueOf() < Date.parse(sDate).valueOf()) {
                    Wx = weatherArr[wxIdx].time[tIdx].parameter.parameterName
                    break
                  }
                }
              }
            }
            for (var wxpIdx in weatherArr) {
              if (weatherArr[wxpIdx].elementName === 'PoP') {
                let sDate = weatherArr[wxpIdx].time[tIdx].startTime
                let eDate = weatherArr[wxpIdx].time[tIdx].endTime
                if ((Date.parse(today).valueOf() >= Date.parse(sDate).valueOf()) && (Date.parse(today).valueOf() < Date.parse(eDate).valueOf())) {
                  WxValue = weatherArr[wxpIdx].time[tIdx].parameter.parameterName
                  break
                } else {
                  if (Date.parse(today).valueOf() < Date.parse(sDate).valueOf()) {
                    WxValue = weatherArr[wxpIdx].time[tIdx].parameter.parameterName
                    break
                  }
                }
              }
            }
            // console.log(minT + '@' + maxT)
            vm.countryArr.push({key: index, name: lnam, minT: minT, maxT: maxT, rain: WxValue, weather: Wx})
          }
        })
        .catch(function (error) {
          console.log(error)
        })
    },
    getTemper () {
      var vm = this
      vm.locationName = ''
      vm.nowTemper = ''
      vm.nowWeather = ''
      vm.weatherClass = 'bi-sun-fill'
      var id = 'O-A0003-001'
      this.$axios
        .get(`https://opendata.cwb.gov.tw/api/v1/rest/datastore/${id}?Authorization=CWB-566765E6-6F28-488F-9C87-1A3B3959DC81&format=JSON`)
        .then(function (response) {
          console.log(response.data.records.location)
          let lcData = response.data.records.location
          for (var index in lcData) {
            if (lcData[index].locationName === '梧棲') {
              vm.locationName = lcData[index].locationName
              let weatherArr = lcData[index].weatherElement
              for (var wxpIdx in weatherArr) {
                if (weatherArr[wxpIdx].elementName === 'TEMP') {
                  vm.nowTemper = weatherArr[wxpIdx].elementValue
                }
                if (weatherArr[wxpIdx].elementName === 'Weather') {
                  vm.nowWeather = weatherArr[wxpIdx].elementValue
                  if (vm.nowWeather === '-99') {
                    vm.nowWeather = ''
                  }
                  // 多雲 class:bi-clouds-fill
                  if (vm.nowWeather.indexOf('雲') !== -1) {
                    vm.weatherClass = 'bi-clouds-fill'
                  }
                  // 陰 class:bi-cloud-sun-fill
                  if (vm.nowWeather.indexOf('陰') !== -1) {
                    vm.weatherClass = 'bi-cloud-sun-fill'
                  }
                  // 靄 class:bi-cloud-fog-fill
                  if (vm.nowWeather.indexOf('靄') !== -1) {
                    vm.weatherClass = 'bi-cloud-fog-fill'
                  }
                  // 下雨 class:bi-cloud-rain-fill
                  if (vm.nowWeather.indexOf('雨') !== -1) {
                    vm.weatherClass = 'bi-cloud-rain-fill'
                  }
                  // 下雪 class:bi-cloud-snow-fill
                  if (vm.nowWeather.indexOf('雪') !== -1) {
                    vm.weatherClass = 'bi-cloud-snow-fill'
                  }
                  // 晴 class:bi-sun-fill
                  if (vm.nowWeather.indexOf('晴') !== -1) {
                    vm.weatherClass = 'bi-sun-fill'
                  }
                }
              }
            }
          }
        })
        .catch(function (error) {
          console.log(error)
        })
    },
    getCountryWeather () {
      var vm = this
      console.log('getCountryWeather===>' + vm.countryValue)
      for (var cIdx in vm.countryArr) {
        if (vm.countryArr[cIdx]['key'] === vm.countryValue) {
          // console.log(vm.countryArr[cIdx])
          vm.getNowData['location'] = vm.countryArr[cIdx]['name']
          vm.getNowData['minT'] = vm.countryArr[cIdx]['minT']
          vm.getNowData['maxT'] = vm.countryArr[cIdx]['maxT']
          vm.getNowData['rain'] = vm.countryArr[cIdx]['rain']
          vm.getNowData['weather'] = vm.countryArr[cIdx]['weather']
        }
      }
    }
  }
}
</script>

<style>
.weatherDiv {
  box-shadow:2px 2px 5px 1px #c5c0c0;
  border-radius: 5px;
  border-width:5px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#FFFFFF;
  padding: 5px;
  width: 300px;
  justify-content: center;
}
.temperDiv {
  border-radius: 7px;
  border-width:5px;
  border-style:solid;
  border-color:rgb(166, 220, 241);
  background-color:rgb(166, 220, 241);
  float: left;
  width: 120px;
  height: 105px;
  text-align: center;
  line-height: 20px;
}
.picDiv {
  border-radius: 7px;
  border-width:5px;
  border-style:solid;
  border-color:rgb(166, 220, 241);
  background-color:rgb(166, 220, 241);
  float: left;
  width: 120px;
  text-align: center;
}
[class^='bi'] {
  font-size: 47px;
}
</style>



