<template>
  <div>
    <div class="card">
      <h2>練習一</h2>
      <div>
        <table width="70%" cellpadding="2px">
          <tr>
            <td width="25%" style="font-weight:bold;">品項</td>
            <td width="20%" style="font-weight:bold;" align="center">價格</td>
            <td width="25%" style="font-weight:bold;" align="center">數量</td>
            <td width="20%" style="font-weight:bold;" align="right">總額</td>
            <td width="10%"></td>
          </tr>
          <tr v-for="(drinkItem, drinkIdx) in drinkList" :key="drinkIdx">
            <td>{{ drinkItem.name }}</td>
            <td align="center">{{ drinkItem.price }}</td>
            <td align="center"><input type="button" value="-" @click="reduceCups(drinkItem)"> <input type="text" size="1" v-model="drinkItem.count"> <input type="button" value="+" @click="addCups(drinkItem)"></td>
            <td align="right">{{ drinkItem.price * drinkItem.count}}</td>
            <td align="center"><input type="button" value="刪除" @click="deltDrink(drinkItem)"></td>
          </tr>
          <tr>
            <td></td>
            <td></td>
            <td style="font-weight:bold;" align="center">共 {{ getDrink.count }} 杯</td>
            <td style="font-weight:bold;" align="right">Total $ {{ getDrink.total }}</td>
            <td></td>
          </tr>
        </table>
      </div>
    </div>
    <div class="card">
      <h2>練習二</h2>
      <div>
        <div style="float:left;width:350px;text-align:left;">
          <h3>童童幼稚園人員表</h3>
          <p>姓名：<input type="text" v-model="childName"></p>
          <p>年齡：<input type="text" v-model="childAge"></p>
          <p>性別：<input type="radio" v-model="childSex" value="M" id="childSexM"><label for="childSexM">男</label> <input type="radio" v-model="childSex" value="F" id="childSexF"><label for="childSexF">女</label></p>
          <p>身高：<input type="text" v-model="childHeight"></p>
          <input type="button" value="送出" @click="addChildList">
        </div>
        <div style="float:left;width:50px;"><p></p></div>
        <div style="float:left;width:400px;">
          <br>
          <table width="100%">
            <tr>
              <td width="25%" align="center">姓名</td>
              <td width="25%" align="center">年齡<input type="button" value="排序" @click="sortChild('age')"></td>
              <td width="25%" align="center">性別</td>
              <td width="25%" align="center">身高<input type="button" value="排序" @click="sortChild('height')"></td>
            </tr>
            <tr v-for="(person, childIdx) in childList" :key="childIdx">
              <td align="center">{{ person.name}} </td>
              <td align="center">{{ person.age}} </td>
              <td align="center">{{ person.sex}} </td>
              <td align="center">{{ person.height}} </td>
            </tr>
          </table>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day5',
  data () {
    return {
      drinkList: [
        {'name': '白玉歐蕾', 'price': 65, 'count': 3},
        {'name': '決明子紅茶', 'price': 45, 'count': 6},
        {'name': '伯爵巧克力奶', 'price': 55, 'count': 4},
        {'name': '甘蔗青茶', 'price': 35, 'count': 10},
        {'name': '黑糖珍珠鮮奶', 'price': 50, 'count': 3},
        {'name': '檸檬綠茶', 'price': 40, 'count': 8}],
      childName: '',
      childAge: '',
      childSex: '',
      childHeight: '',
      childList: [],
      ageRate: 1,
      heightRate: 1
    }
  },
  computed: {
    getDrink: function () {
      var vm = this
      var drinkSum = {'count': 0, 'total': 0}
      vm.drinkList.forEach(function (item) {
        drinkSum.count += parseInt(item['count'])
        drinkSum.total += (item['count'] * item['price'])
      })
      return drinkSum
    }
  },
  methods: {
    reduceCups (drinkItem) {
      if (drinkItem['count'] === 0) {
        return
      }
      var vm = this
      vm.drinkList.forEach(function (item) {
        if (drinkItem['name'] === item['name']) {
          item['count']--
        }
      })
    },
    addCups (drinkItem) {
      var vm = this
      vm.drinkList.forEach(function (item) {
        if (drinkItem['name'] === item['name']) {
          item['count']++
        }
      })
    },
    deltDrink (drinkItem) {
      var vm = this
      vm.drinkList.forEach(function (item, index) {
        if (drinkItem['name'] === item['name']) {
          vm.drinkList.splice(index, 1)
        }
      })
    },
    addChildList () {
      var vm = this
      if (!vm.childName || !vm.childAge || !vm.childSex || !vm.childHeight) {
        alert('請輸入姓名、年齡、性別、身高')
      } else {
        vm.childList.push({'name': vm.childName, 'age': vm.childAge, 'sex': (vm.childSex === 'M' ? '男' : '女'), 'height': vm.childHeight})
        vm.childName = ''
        vm.childAge = ''
        vm.childSex = ''
        vm.childHeight = ''
      }
    },
    sortChild (fied) {
      var vm = this
      var rate = (fied === 'age') ? vm.ageRate : vm.heightRate
      // eslint-disable-next-line
      var newData = this.childList
      newData = newData.sort(function (a, b) {
        // 抓出排序資料的值
        a = a[fied]
        b = b[fied]
        return (a === b ? 0 : a > b ? 1 : -1) * rate
      })
      if (fied === 'age') {
        vm.ageRate = vm.ageRate * -1
      } else {
        vm.heightRate = vm.heightRate * -1
      }
    }
  }
}
</script>

<style>
</style>



