<template>
  <div>
    <div class="card" style="text-align:left;">
      <h2>練習一</h2>
      <div>
        <span v-for="(countryItm, countryIdx) in countryList" :key="countryIdx">
            <country-component :country-value="countryIdx" @clickcountry="calTotalCountry"></country-component>
        </span>
        <p>全球總人數：{{ totalPeople }}</p>
      </div>
    </div>
    <div class="card" style="width:1400px;">
      <h2>練習二</h2>
      <div>
        <div style="float:left;">
          <div style="height:50px;">
            <input type="button" class="menuBtnClass" v-for="(menuItm, menuIdx) in menuType" :value="menuItm.name" :key="menuIdx" @click="changeMenuTitle(menuItm)">
          </div>
          <div id="divPandaClass">
            <buypanda-component :panda-title="menuTitle" :panda-rice="rice" :panda-noodles="noodles" :panda-soup="soup" :panda-beverage="beverage" @clickpanda="addCarItems"></buypanda-component>
          </div>
        </div>
        <div style="float:left;text-align:left;">
          <br>
          <p style="font-size:3vmin;font-weight: bold;">購物車</p>
          <table width="100%">
            <tr v-for="(cItems, cIdx) in carItems" :key="cIdx">
              <td width="5%"><input type="button" value="刪" @click="deleteCars(cItems)"></td>
              <td width="30%">{{ cItems.item }}</td>
              <td width="10%" align="center"><input type="button" value="-" @click="reduceCars(cItems)"></td>
              <td width="5%" align="center">{{ cItems.count }}</td>
              <td width="10%" align="center"><input type="button" value="+" @click="addCars(cItems)"></td>
              <td width="10%" align="right">{{ cItems.cost }}</td>
              <td width="20%" align="right">{{ cItems.total }}</td>
            </tr>
          </table>
          <hr width="500px">
          <table width="100%" style="font-size:2vmin;font-weight: bold;">
            <tr>
              <td>小計：</td>
              <td align="right">{{ carCost }}</td>
            </tr>
            <tr>
              <td>服務費：</td>
              <td align="right">{{ serviceCharge }}</td>
            </tr>
            <tr>
              <td>總計：</td>
              <td align="right">{{ carTotal }}</td>
            </tr>
          </table>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day8',
  data () {
    return {
      countryList: {'中國': 0, '美國': 0, '義大利': 0},
      totalPeople: 0,
      carItems: [],
      carCost: 0,
      serviceCharge: 0,
      carTotal: 0,
      menuTitle: '',
      menuType: [
        {'type': 'rice', 'name': '飯類/rice'},
        {'type': 'noodles', 'name': '麵類/noodles'},
        {'type': 'soup', 'name': '湯類/soup'},
        {'type': 'beverage', 'name': '飲料/beverage'}],
      rice: [
        {name: '滷肉飯', price: 35},
        {name: '雞肉飯', price: 30},
        {name: '鴨肉飯', price: 30},
        {name: '燒肉飯', price: 45}],
      noodles: [
        {name: '乾麵', price: 35},
        {name: '麻醬麵', price: 35},
        {name: '餛飩麵', price: 55},
        {name: '鍋燒烏龍麵', price: 75},
        {name: '鍋燒意麵', price: 75},
        {name: '榨菜肉絲麵', price: 50}],
      soup: [
        {name: '貢丸湯', price: 25},
        {name: '粉腸湯', price: 35},
        {name: '菜頭湯', price: 20},
        {name: '青菜豆腐湯', price: 30},
        {name: '油豆腐湯', price: 35},
        {name: '綜合湯', price: 50}],
      beverage: [
        {name: '可樂', price: 25},
        {name: '雪碧', price: 25},
        {name: '綠茶', price: 20},
        {name: '紅茶', price: 20}]
    }
  },
  components: {
    'buypanda-component': {
      props: ['pandaTitle', 'pandaRice', 'pandaNoodles', 'pandaSoup', 'pandaBeverage'],
      template: ` <div>
                      <div style="float:left;height:150px;" v-for="(eatItm, eatIdx) in getMemuList" :key="eatItm.name">
                          <div class="divPandaBoxClass">
                              <div>
                                  <div style="float:left;width:120px;">
                                      <p>{{ eatItm.name }}</p>
                                      <p>NT$ {{ eatItm.price }}</p>
                                  </div>
                                  <div style="float:left;">
                                      <input type="button" class="pandaBtnClass" value="+" @click="addShopitems(eatItm)">
                                  </div>
                              </div>
                          </div>
                          <div style="width:30px;float:left;">&emsp;</div>
                      </div>
                  </div>
                  `,
      computed: {
        getMemuList: function () {
          var vm = this
          var newMenu = []
          if (vm.pandaTitle === 'rice') {
            newMenu = vm.pandaRice
          } else if (vm.pandaTitle === 'noodles') {
            newMenu = vm.pandaNoodles
          } else if (vm.pandaTitle === 'soup') {
            newMenu = vm.pandaSoup
          } else if (vm.pandaTitle === 'beverage') {
            newMenu = vm.pandaBeverage
          }
          return newMenu
        }
      },
      methods: {
        addShopitems (item) {
          this.$emit('clickpanda', item)
        }
      }
    },
    'country-component': {
      props: ['countryValue'],
      template: ` <div>
                      <p>{{ countryValue }}疫情人數：
                          <input type="text" size="5" v-model.number="compCount" @change="addEpids">
                          <input type="button" value="add" @click="addEpids">
                          目前累積人數：{{ compCount }}
                      </p>
                  </div>
                `,
      data () {
        return {
          compCount: 0
        }
      },
      methods: {
        addEpids: function (event) {
          // 撈取事件類型
          var type = event.type
          if (type === 'click') {
            this.compCount++
          }
          this.$emit('clickcountry', this.countryValue, this.compCount)
        }
      }
    }
  },
  methods: {
    calTotalCountry (val, count) {
      var vm = this
      var total = 0
      vm.countryList[val] = count
      for (var item in vm.countryList) {
        total += vm.countryList[item]
      }
      vm.totalPeople = total
    },
    changeMenuTitle (itm) {
      this.menuTitle = itm.type
    },
    calCarsTotal () {
      var vm = this
      vm.carCost = 0
      vm.carItems.forEach((el, idx) => {
        vm.carCost += el.total
      })
      vm.serviceCharge = 30
      vm.carTotal = vm.carCost + vm.serviceCharge
    },
    addCarItems (getItem) {
      var vm = this
      var getIndex = ''
      var isExists = false
      vm.carItems.forEach((el, idx) => {
        if (el.item === getItem.name) {
          getIndex = idx
          isExists = true
        }
      })
      if (isExists) {
        vm.carItems[getIndex]['count'] += 1
        vm.carItems[getIndex]['total'] = vm.carItems[getIndex]['count'] * vm.carItems[getIndex]['cost']
      } else {
        vm.carItems.push({'item': getItem.name, 'count': 1, 'cost': getItem.price, 'total': getItem.price})
      }
      this.calCarsTotal()
    },
    deleteCars (getItem) {
      var vm = this
      vm.carItems.forEach(function (item, idx) {
        if (getItem['item'] === item['item']) {
          vm.carItems.splice(idx, 1)
        }
      })
      this.calCarsTotal()
    },
    reduceCars (getItem) {
      if (getItem['count'] === 0) {
        return
      }
      var vm = this
      vm.carItems.forEach(function (item, idx) {
        if (getItem['item'] === item['item']) {
          item['count']--
          item['total'] = item['count'] * item['cost']
          if (item['count'] === 0) {
            vm.carItems.splice(idx, 1)
          }
        }
      })
      this.calCarsTotal()
    },
    addCars (getItem) {
      var vm = this
      vm.carItems.forEach(function (item) {
        if (getItem['item'] === item['item']) {
          item['count']++
          item['total'] = item['count'] * item['cost']
        }
      })
      this.calCarsTotal()
    }
  }
}
</script>

<style>
.menuBtnClass {
  font-size: 3vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  background-color: #FFFFFF;
  border: 0px solid #FFFFFF;
  cursor: pointer;
}
.menuBtnClass:hover, .menuBtnClass:focus {
  color:olivedrab;
}
.pandaBtnClass {
  color: #FFFFFF;
  background-color: rgb(214, 38, 132);
  border: 0px solid rgb(214, 38, 132);
  cursor: pointer;
  height: 20px;
  width: 20px;
  padding: 0px;
}
#divPandaClass {
  border-width:0px;
  border-style:solid;
  padding:2px;
  width:800px;
  display:flex;
  flex-wrap:wrap;
  justify-content:flex-start;
}
.divPandaBoxClass {
  box-shadow:2px 2px 5px 1px #c5c0c0;
  border-width:5px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#FFFFFF;
  padding:2px;
  width:160px;
  float:left;
  text-align: left;
}
</style>



