<template>
  <div>
    <div class="card" style="text-align:left;">
      <h2>練習一－代辦清單</h2>
        <div class="taskID01">
          <table width="100%">
            <tr>
              <td width="100px" valign="top">代辦任務</td>
              <td><textarea v-model="task" placeholder="請輸入任務" style="width:500px;"></textarea></td>
            </tr>
            <tr>
              <td>交辦日期</td>
              <td><input type="date" v-model="assDate"></td>
            </tr>
            <tr>
              <td>交辦人員</td>
              <td><input type="text" v-model="assEmpNo" placeholder="請輸入交辦人員"></td>
            </tr>
            <tr>
              <td>緊急度</td>
              <td><select name="urgency" v-model="urgency"><option v-for="(index, urKey) in urgencyArr" :key="urKey">{{index.type}}</option></select></td>
            <tr>
              <td>處理狀態</td>
              <td><select name="state" v-model="state"><option v-for="(index, stateKey) in getStateArr" :key="stateKey">{{index.type}}</option></select></td>
            </tr>
          </table>
        </div>
        <div class="taskID02">
          <table>
            <tr>
              <td><button class="btn01" @click="setTask">新增</button></td>
              <td><button class="btn02" @click="clnData">清空</button></td>
            </tr>
          </table>
        </div>
        <h1>任務清單</h1>
        <div id="taskID04">
          <table>
            <tr>
              <td v-for="(stateIdx, sKey) in stateArr" :key="sKey">
                <button class="btn03" :id="stateIdx.id" @click="setListShow(stateIdx.id)">{{ stateIdx.type }}﹙{{ listCount[stateIdx.value] }}﹚</button>
              </td>
            </tr>
          </table>
        </div>
        <div class="taskID03">
          <table class="tbl01" width='90%' border='1'>
            <tr>
              <td width='60%'>任務</td>
              <td width='10%'>交辦日期</td>
              <td width='10%'>交辦人員</td>
              <td width='10%'>緊急度</td>
              <td width='10%'>處理狀態</td>
            </tr>
          </table>
          <table class="tbl02" width='90%' border='1'>
            <tr :id="index.id" style="display:'';" v-for="(index, gKey) in getList" :key="'gKey' + gKey">
              <td width='60%'>{{ index.task }}</td>
              <td width='10%'>{{ index.assDate }}</td>
              <td width='10%'>{{ index.assEmpNo }}</td>
              <td width='10%'>{{ index.urgency }}</td>
              <td width='10%'>{{ index.state }}</td>
            </tr>
            <tr :id="index1.id" style="display:none;" v-for="(index1, gKey1) in getList01" :key="'gKey1' + gKey1">
              <td width='60%'>{{ index1.task }}</td>
              <td width='10%'>{{ index1.assDate }}</td>
              <td width='10%'>{{ index1.assEmpNo }}</td>
              <td width='10%'>{{ index1.urgency }}</td>
              <td width='10%'>{{ index1.state }}</td>
            </tr>
            <tr :id="index2.id" style="display:none;" v-for="(index2, gKey2) in getList02" :key="'gKey2' + gKey2">
              <td width='60%'>{{ index2.task }}</td>
              <td width='10%'>{{ index2.assDate }}</td>
              <td width='10%'>{{ index2.assEmpNo }}</td>
              <td width='10%'>{{ index2.urgency }}</td>
              <td width='10%'>{{ index2.state }}</td>
            </tr>
            <tr :id="index3.id" style="display:none;" v-for="(index3, gKey3) in getList03" :key="'gKey3' + gKey3">
              <td width='60%'>{{ index3.task }}</td>
              <td width='10%'>{{ index3.assDate }}</td>
              <td width='10%'>{{ index3.assEmpNo }}</td>
              <td width='10%'>{{ index3.urgency }}</td>
              <td width='10%'>{{ index3.state }}</td>
            </tr>
            <tr :id="index4.id" style="display:none;" v-for="(index4, gKey4) in getList04" :key="'gKey4' + gKey4">
              <td width='60%'>{{ index4.task }}</td>
              <td width='10%'>{{ index4.assDate }}</td>
              <td width='10%'>{{ index4.assEmpNo }}</td>
              <td width='10%'>{{ index4.urgency }}</td>
              <td width='10%'>{{ index4.state }}</td>
            </tr>
          </table>
        </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day9',
  data () {
    return {
      task: '',
      assDate: '',
      assEmpNo: '',
      stateArr: [
        {'type': 'All', 'value': '0', 'id': 'stateID00'},
        {'type': 'Todo', 'value': '1', 'id': 'stateID01'},
        {'type': 'Doing', 'value': '2', 'id': 'stateID02'},
        {'type': 'Waiting', 'value': '3', 'id': 'stateID03'},
        {'type': 'Done', 'value': '4', 'id': 'stateID04'}],
      state: 'Todo',
      urgencyArr: [
        {'type': '一般件', 'value': '1'},
        {'type': '急件', 'value': '2'},
        {'type': '超急件', 'value': '3'}],
      urgency: '一般件',
      getList: [],
      getList01: [],
      getList02: [],
      getList03: [],
      getList04: [],
      listCount: [0, 0, 0, 0, 0]
    }
  },
  computed: {
    getStateArr: function () {
      var vm = this
      var newArr = vm.stateArr.filter(function (element, index, arr) {
        return element.value !== '0'
      })
      return newArr
    }
  },
  methods: {
    setTask () {
      if (this.task && this.assDate) {
        var pushArr = ''
        var pushID = ''
        var xState = this.state
        var countKey = 0
        if (xState === 'Todo') {
          pushArr = this.getList01
          pushID = 'task01'
          countKey = 1
        } else if (xState === 'Doing') {
          pushArr = this.getList02
          pushID = 'task02'
          countKey = 2
        } else if (xState === 'Waiting') {
          pushArr = this.getList03
          pushID = 'task03'
          countKey = 3
        } else {
          pushArr = this.getList04
          pushID = 'task04'
          countKey = 4
        }
        this.listCount[0] += 1
        this.listCount[countKey] += 1
        pushArr.push({'id': pushID + this.listCount[countKey], 'task': this.task, 'assDate': this.assDate, 'assEmpNo': this.assEmpNo, 'state': this.state, 'urgency': this.urgency})
        this.getList.push({'id': 'task00' + this.listCount[0], 'task': this.task, 'assDate': this.assDate, 'assEmpNo': this.assEmpNo, 'state': this.state, 'urgency': this.urgency})
      }
    },
    clnData () {
      this.task = ''
      this.assDate = ''
      this.assEmpNo = ''
      this.state = 'Todo'
      this.urgency = '一般件'
    },
    setListShow (xID) {
      if (xID === 'stateID00') {
        document.querySelectorAll("[id^='task00']").forEach(el => {
          document.getElementById(el.id).style.display = ''
        })
        document.querySelectorAll("[id^='task01']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task02']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task03']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task04']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
      } else if (xID === 'stateID01') {
        document.querySelectorAll("[id^='task00']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task01']").forEach(el => {
          document.getElementById(el.id).style.display = ''
        })
        document.querySelectorAll("[id^='task02']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task03']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task04']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
      } else if (xID === 'stateID02') {
        document.querySelectorAll("[id^='task00']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task01']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task02']").forEach(el => {
          document.getElementById(el.id).style.display = ''
        })
        document.querySelectorAll("[id^='task03']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task04']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
      } else if (xID === 'stateID03') {
        document.querySelectorAll("[id^='task00']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task01']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task02']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task03']").forEach(el => {
          document.getElementById(el.id).style.display = ''
        })
        document.querySelectorAll("[id^='task04']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
      } else {
        document.querySelectorAll("[id^='task00']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task01']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task02']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task03']").forEach(el => {
          document.getElementById(el.id).style.display = 'none'
        })
        document.querySelectorAll("[id^='task04']").forEach(el => {
          document.getElementById(el.id).style.display = ''
        })
      }
    }
  }
}
</script>

<style>
.btn01 {
  font-size: 2vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  border: 0px;
  box-shadow: 0px 5px 0px 0px #3C93D5;
  padding: 0.4rem 0.8rem 0.4rem 0.8rem;
  border-radius: 10px;
  cursor: pointer;
  background-color: #1760b4;
  color: #FFFFFF;
}
.btn01:hover {
  background-color: #50bce7;
  color: #000000;
}
.btn02 {
  font-size: 2vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  border: 0px;
  box-shadow: 0px 5px 0px 0px #8f8e8e;
  padding: 0.4rem 0.8rem 0.4rem 0.8rem;
  border-radius: 10px;
  cursor: pointer;
  background-color: #515053;
  color: #FFFFFF;
}
.btn02:hover {
  background-color: #c7c6c6;
  color: #000000;
}
.btn03 {
  font-size: 1.6vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  border: 0px;
  box-shadow: 0px 5px 0px 0px rgb(158, 145, 145);
  padding: 0.4rem 0.8rem 0.4rem 0.8rem;
  border-radius: 10px;
  cursor: pointer;
  background-color: #51aed3;
  color: #FFFFFF;
}
.btn03:hover {
  background-color: #8bd9f8;
  color: #000000;
}
.taskID01, .taskID02 {
  font-size: 2vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  color: blue;
}
.tbl01 {
  font-size: 2vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  color: #FFFFFF;
  background-color: rgb(158, 145, 145);
  border: 0px #FFFFFF;
  border-radius: 10px;
  border-spacing: 0px;
  border-collapse: collapse;
  text-align: center;
}
.tbl02 {
  font-size: 2vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  color: #000000;
  background-color: rgb(236, 232, 232);
  border: 0px #FFFFFF;
  border-radius: 2px;
  border-spacing: 0px;
  border-collapse: collapse;
  text-align: center;
}
</style>



