<template>
  <div>
    <div class="card" style="text-align:left;">
      <h2>練習一</h2>
      <div>
        <input type="button" value="click me 呼叫 API" @click="getData">
        <p>回傳結果：</p>
        <p>{{ getApiData }}</p>
      </div>
    </div>
  </div>
</template>

<script>
const Base64 = require('js-base64').Base64

export default {
  name: 'day13',
  data () {
    return {
      getApiData: ''
    }
  },
  methods: {
    getData () {
      var vm = this
      vm.getApiData = ''
      // get API 資料
      // this.$axios
      //   .get('http://10.6.51.133/EIP/gows.php?wtag=lib.cg.getDrugBasicData')
      //   .then(function (response) {
      //     // status 2000 呼叫成功
      //     console.log(response)
      //     let result = JSON.parse(Base64.decode(response.data))
      //   })
      //   .catch(function (error) {
      //     console.log(error)
      //   })
      var api = 'http://10.6.51.133/EIP/gows.php'
      var tag = 'lib.cg.getDrugBasicData'
      let param = new FormData()
      let conf = {
        params: {
          wtag: tag
        }
      }
      let obj = {
        wb_base64: 0,
        encode: 'N',
        drug_cod: 'IDAN',
        typ: 'PS'
      }
      param.append('var', Base64.encode(JSON.stringify(obj)))
      // 傳入參數回傳結果
      this.$axios
        .post(api, param, conf)
        .then(function (response) {
          // status 2000 呼叫成功
          // console.log(response)
          let result = JSON.parse(Base64.decode(response.data))
          console.log(result)
          if (result.sts === '000000') {
            console.log('呼叫WS成功===>')
            let getVal = result.val.txt
            if (getVal) {
              vm.getApiData = Base64.decode(getVal)
              console.log(vm.getApiData)
            }
          } else {
            console.log(result.sts, result.msg)
          }
        })
        .catch(function (error) {
          console.log(error)
        })
    }
  }
}
</script>

