<template>
  <div>
    <div class="card">
      <h2>練習一－展覽資訊</h2>
      <div>
        <div class="exhibDiv" v-for="(apiItem, apiKey) in getApiData" :key="'apiKey' + apiKey" @click="turnInforPage(apiItem)">
          {{ apiItem.title }}<br>{{ apiItem.showInfo[0].location }}
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day12',
  data () {
    return {
      getApiData: null
    }
  },
  created () {
    // this.$http.get(`https://cloud.culture.tw/frontsite/trans/SearchShowAction.do?method=doFindTypeJ&category=6`).then((response) => {
    //   // console.log(response)
    //   for (var index in response) {
    //     if (index === 'data') {
    //       for (var list in response[index]) {
    //         console.log(response[index][list])
    //       }
    //     }
    //   }
    // })
  },
  mounted () {
    var vm = this
    this.$axios
      .get('https://cloud.culture.tw/frontsite/trans/SearchShowAction.do?method=doFindTypeJ&category=6')
      .then(function (response) {
        // console.log(response['data'])
        vm.getApiData = response['data']
      })
      .catch(function (error) {
        console.log(error)
      })
  },
  methods: {
    turnInforPage (item) {
      // console.log(item)
      this.$router.push({
        name: 'detail',
        path: '/page/detail',
        params: {
          item
        }
      })
    }
  }
}
</script>

<style>
.exhibDiv {
  background-color:teal;
  color: #FFFFFF;
  border: 1px solid rgb(95, 121, 121);
  padding: 5px;
  cursor: pointer;
}
.exhibDiv:hover {
  background-color:rgb(43, 185, 185);
}
</style>



