<template>
  <div>
    <div class="card">
      <div v-if="getItem">
        <table>
          <tr>
            <td><h3>{{ getItem.title }}</h3></td>
            <td><input type="button" class="homeBtn" value="回首頁" @click="turnHome"></td>
          </tr>
          <tr>
            <td><h5>展覽期間：{{ getItem.startDate }}～{{ getItem.endDate }}</h5></td>
          </tr>
          <tr v-if="getItem.showInfo">
            <td><h5>地點：{{ getItem.showInfo[0].locationName }}／{{ getItem.showInfo[0].location }}</h5></td>
          </tr>
          <tr v-if="getItem.descriptionFilterHtml">
            <td>描述：{{ getItem.descriptionFilterHtml }}</td>
          </tr>
        </table>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'detail',
  data () {
    return {
      getItem: []
    }
  },
  mounted () {
    if (this.$route.params.item !== undefined) {
      console.log('get')
      console.log(this.$route.params.item)
      this.getItem = this.$route.params.item
    }
  },
  methods: {
    turnHome () {
      this.$router.push('/page/day12')
    }
  }
}
</script>

<style>
.exhibDiv {
  background-color:teal;
  color: #FFFFFF;
  border: 1px solid rgb(95, 121, 121);
  padding: 5px;
  cursor: pointer;
}
.exhibDiv:hover {
  background-color:rgb(43, 185, 185);
}
.homeBtn {
  background-color:firebrick;
  color:floralwhite;
  border: 1px solid firebrick;
  padding: 2px 10px 2px 10px;
  cursor: pointer;
  border-radius: 4px;
  font-weight: bold;
}
.homeBtn:hover {
  background-color:rgb(236, 68, 68);
}
</style>



