<template>
  <div>
    <div class="card" style="text-align:left;">
      <h2>練習一－99 乘法表</h2>
      <div style="padding-left: 20px;">
        <p>請輸入數字：<input type="text" v-model.number="multipValue" size="5"></p>
        <div class="multipClass" v-if="multipValue">
          <div v-for="mValue in 9" :key="mValue" class="multipDetailClass">
            <p v-for="dValue in 9" :key="dValue">
                {{ multipValue }} * {{ mValue }} * {{ dValue }} = {{ multipValue * dValue * mValue}}
            </p>
          </div>
        </div>
      </div>
      <h2>練習二－房型清單</h2>
      <div class="houseDiv">
        <div class="houseDiv01">
          <p style="font-size: 3vmin;"><b>房型介紹</b></p>
        </div>
        <div>
          <div class="houseDiv02" v-for="(houseItem, houseIdx) in houseList" :key="houseIdx">
            <house-component :house-component-item="houseItem"></house-component>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import imageA from '../../assets/apple.jpg'
import imageB from '../../assets/kiwi.jpg'
import imageC from '../../assets/mango.jpg'
import imageD from '../../assets/melon.jpg'
import imageE from '../../assets/orange.jpg'

export default {
  name: 'day11',
  data () {
    return {
      multipValue: '',
      houseList: [
        {
          roomType: '雙人房',
          roomName: '海景風格-一般房型',
          weekdayPrice: '1200',
          weekendPrice: '1800',
          content: '不含早餐、位於3樓、海景、衛浴位於房內、乾濕分離衛浴、1 張雙人床、不可加人',
          detail: ['樓層：位於3樓', '床型：1 張雙人床', '家電用品：冷氣、電扇', '戶外：景觀陽台、躺椅', '飲品茶點：小點心、茶、咖啡', '衛浴型式：乾濕分離衛浴', '其他：書籍、雜誌、無線網路'],
          image: imageA
        },
        {
          roomType: '雙人房',
          roomName: '山景風格-一般房型',
          weekdayPrice: '1000',
          weekendPrice: '1200',
          content: '不含早餐、位於3樓、山景、衛浴位於房內、乾濕分離衛浴、2 張單人床、不可加人',
          detail: ['樓層：位於3樓', '床型：2 張單人床', '家電用品：冷氣、電扇', '戶外：景觀陽台、躺椅', '飲品茶點：小點心、茶、咖啡', '衛浴型式：乾濕分離衛浴', '其他：書籍、雜誌、無線網路'],
          image: imageB
        },
        {
          roomType: '四人房',
          roomName: '海景風格-樓中樓',
          weekdayPrice: '2400',
          weekendPrice: '3600',
          content: '不含早餐、位於2樓、海景、衛浴位於房內、乾濕分離衛浴、2 張雙人床、不可加人',
          detail: ['樓層：位於2樓', '床型：2 張雙人床', '家電用品：冷氣、電扇', '戶外：景觀陽台、躺椅', '飲品茶點：小點心、茶、咖啡', '衛浴型式：乾濕分離衛浴', '其他：書籍、雜誌、無線網路'],
          image: imageC
        },
        {
          roomType: '四人房',
          roomName: '山景風格-樓中樓',
          weekdayPrice: '2000',
          weekendPrice: '3200',
          content: '不含早餐、位於2樓、海景、衛浴位於房內、乾濕分離衛浴、2 張雙人床、不可加人',
          detail: ['樓層：位於2樓', '床型：2 張雙人床', '家電用品：冷氣、電扇', '戶外：景觀陽台、躺椅', '飲品茶點：小點心、茶、咖啡', '衛浴型式：乾濕分離衛浴', '其他：書籍、雜誌、無線網路'],
          image: imageD
        },
        {
          roomType: '六人房',
          roomName: '海景風格-大通舖',
          weekdayPrice: '3600',
          weekendPrice: '4800',
          content: '不含早餐、位於1樓、海景、衛浴位於房內、乾濕分離衛浴、3 張雙人床、不可加人',
          detail: ['樓層：位於1樓', '床型：3 張雙人床', '家電用品：冷氣、電扇', '戶外：景觀陽台、躺椅', '飲品茶點：小點心、茶、咖啡', '衛浴型式：乾濕分離衛浴', '其他：書籍、雜誌、無線網路'],
          image: imageE
        }]
    }
  },
  components: {
    'house-component': {
      props: ['houseComponentItem'],
      template: ` <div>
                    <table class="houseDiv03" width="100%">
                        <tr>
                            <td width="50px" align="center"><img :src="houseComponentItem.image" style="width:150px;"></td>
                            <td width="700px">
                                <table>
                                    <tr v-if="showHouseContent">
                                        <td width="500px" valign="top">
                                            {{ houseComponentItem.roomName }}<br>
                                            {{ houseComponentItem.roomType }}<br>
                                            <span style="font-weight: normal;">{{ houseComponentItem.content }}</span><br>
                                            <span style="font-weight: normal;font-size:1.6vmin;color:#707038;" v-if="showHouseDetail">
                                                <hr>
                                                <span v-for="(hDetail, hIdx) in getHouseDetail">
                                                    {{ hDetail }}<br>
                                                </span>
                                            </span
                                        </td>
                                        <td width="200px" valign="top" align="right" style="color:dodgerblue;">
                                            $ {{ houseComponentItem.weekdayPrice }} ~ $ {{ houseComponentItem.weekendPrice }} /房
                                            <br><br>
                                            <input type="button" :value="btnValue" class="houseBtn" @click="showDetail">&emsp;
                                        </td>
                                    </tr>
                                    <tr v-if="!showHouseContent">
                                        <td width="700px" valign="top" align="center" class="houseCheckTd03">
                                            <span @click="showHouse">
                                                {{ houseComponentItem.roomName }}<br>
                                                {{ houseComponentItem.roomType }}<br>
                                                {{ houseComponentItem.weekdayPrice }} ~ {{ houseComponentItem.weekendPrice }}
                                            </span>
                                        </td>
                                    </tr>
                                </table>
                            </td>
                        </tr>
                    </table>
                </div>`,
      methods: {
        showHouse () {
          this.showHouseContent = true
        },
        showDetail () {
          this.showHouseDetail = !this.showHouseDetail
          this.btnValue = this.showHouseDetail ? '點我收起房型明細' : '點我展開房型明細'
        }
      },
      data () {
        return {
          btnValue: '點我展開房型明細',
          showHouseContent: false,
          showHouseDetail: false,
          getHouseDetail: this.houseComponentItem.detail
        }
      }
    }
  }
}
</script>

<style>
.multipClass {
  border-width:2px;
  border-style:solid;
  border-color:#FFFFFF;
  padding:2px;
  display:flex;
  flex-wrap:wrap;
  justify-content:flex-start;
}
.multipDetailClass {
  box-shadow:2px 2px 5px 1px #c5c0c0;
  border-width:5px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#FFFFFF;
  padding:5px;
  float:left;
}
.houseDiv {
  border-width:0px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color: #e2e3e5;
  padding:2px;
  display:flex;
  flex-wrap:wrap;
  justify-content:flex-start;
  float:left;
}
.houseDiv01 {
  border-width:0px;
  border-style:solid;
  border-color:#FFFFFF;
  padding:5px;
  display:flex;
  flex-wrap:wrap;
  justify-content:flex-start;
  float:left;
  width:200px;
}
.houseDiv02 {
  border-width:1px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#e2e3e5;
  padding:5px;
  width:800px;
}
.houseDiv03 {
  border-width:0px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#fdfdfe;
  color:darkslategrey;
  font-weight: bold;
}
.houseBtn {
  font-size: 1.6vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  border: 1px solid #51aed3;
  box-shadow: 2px 2px 5px 1px #c5c0c0;
  padding: 0.2rem 0.4rem 0.2rem 0.4rem;
  border-radius: 10px;
  cursor: pointer;
  background-color: #51aed3;
  color: #FFFFFF;
}
.houseBtn:hover {
  border-color: #51aed3;
  background-color: #FFFFFF;
  color: #51aed3;
}
.houseCheckTd03 {
  border-width:1px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#FFFFFF;
  padding:5px;
  cursor: pointer;
  width:800px;
}
.houseCheckTd03:hover {
  font-weight: bold;
  color:dodgerblue;
}
</style>



